css:
#chart-container {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-size: 12px;
  color: #343d50;
}

script:
function renderChart(data, clickFunc, config) {
  var chartDom = document.getElementById('chart-container');
  if (!chartDom) return;

  var chart = echarts.init(chartDom);
  var table = data && data[0] ? data[0] : [];

  var dateCol = table[0] || { name: '\u65e5\u671f', type: 'string', data: [] };
  var costCol = table[1] || { name: '\u6210\u672c\u4ef7', type: 'number', data: [], numberFormat: null };
  var salesCol = table[2] || { name: '\u9500\u552e\u91d1\u989d', type: 'number', data: [], numberFormat: null };
  var qtyCol = table[3] || { name: '\u8ba2\u8d2d\u6570\u91cf', type: 'number', data: [], numberFormat: null };

  var xData = dateCol.data || [];
  var costData = (costCol.data || []).map(toNumberOrNull);
  var salesData = (salesCol.data || []).map(toNumberOrNull);
  var qtyData = (qtyCol.data || []).map(toNumberOrNull);

  var colors = config && config.colors && config.colors.length >= 3
    ? config.colors
    : ['#5470C6', '#91CC75', '#EE6666'];

  var isDark = config && config.theme === 'DARK';
  var textColor = isDark ? '#DDE3EA' : '#343d50';
  var splitLineColor = isDark ? 'rgba(255,255,255,0.10)' : '#E6EAF2';
  var axisLineColor = isDark ? '#7E8793' : '#AAB4C3';

  function toNumberOrNull(value) {
    if (value == null || value === '') return null;
    var num = Number(value);
    return isNaN(num) ? null : num;
  }

  function fmt(value) {
    if (value == null || value === '') return '-';
    var num = Number(value);
    if (isNaN(num)) return String(value);
    return echarts.format.addCommas(num);
  }

  var option = {
    color: colors,
    animation: true,
    tooltip: {
      trigger: 'axis',
      axisPointer: { type: 'cross' },
      formatter: function (params) {
        if (!params || !params.length) return '';
        var lines = [params[0].axisValueLabel || ''];
        params.forEach(function (item) {
          lines.push(item.marker + item.seriesName + '\uff1a' + fmt(item.value));
        });
        return lines.join('<br/>');
      }
    },
    legend: {
      top: 10,
      data: [costCol.name, salesCol.name, qtyCol.name],
      textStyle: { color: textColor }
    },
    grid: {
      top: 60,
      left: 70,
      right: 130,
      bottom: 50,
      containLabel: false
    },
    xAxis: {
      type: 'category',
      data: xData,
      boundaryGap: true,
      axisLine: { lineStyle: { color: axisLineColor } },
      axisTick: { alignWithLabel: true },
      axisLabel: { color: textColor }
    },
    yAxis: [
      createYAxis(costCol.name, 'left', 0, colors[0], true),
      createYAxis(salesCol.name, 'right', 0, colors[1], false),
      createYAxis(qtyCol.name, 'right', 65, colors[2], false)
    ],
    series: [
      createLineSeries(costCol.name, 0, costData),
      createLineSeries(salesCol.name, 1, salesData),
      createLineSeries(qtyCol.name, 2, qtyData)
    ]
  };

  chart.setOption(option, true);

  chart.off('click');
  chart.on('click', function (params) {
    var columnIndex = 0;
    if (params.seriesName === costCol.name) columnIndex = 1;
    if (params.seriesName === salesCol.name) columnIndex = 2;
    if (params.seriesName === qtyCol.name) columnIndex = 3;

    if (typeof clickFunc === 'function') {
      clickFunc({
        clickItems: [
          {
            idx: [params.dataIndex, columnIndex],
            colName: params.seriesName,
            value: [
              String(xData[params.dataIndex] == null ? '' : xData[params.dataIndex]),
              String(params.value == null ? '' : params.value)
            ]
          }
        ]
      });
    }
  });

  if (window.__tripleAxisResizeHandler) {
    window.removeEventListener('resize', window.__tripleAxisResizeHandler);
  }
  window.__tripleAxisResizeHandler = function () {
    chart.resize();
  };
  window.addEventListener('resize', window.__tripleAxisResizeHandler);

  function createYAxis(name, position, offset, color, showSplitLine) {
    return {
      type: 'value',
      name: name,
      position: position,
      offset: offset,
      axisLine: {
        show: true,
        lineStyle: { color: color }
      },
      axisLabel: {
        color: color,
        formatter: function (value) { return fmt(value); }
      },
      splitLine: {
        show: showSplitLine,
        lineStyle: {
          color: splitLineColor,
          type: 'dashed'
        }
      },
      nameTextStyle: { color: color }
    };
  }

  function createLineSeries(name, yAxisIndex, seriesData) {
    return {
      name: name,
      type: 'line',
      yAxisIndex: yAxisIndex,
      data: seriesData,
      smooth: true,
      symbol: 'circle',
      symbolSize: 7,
      lineStyle: { width: 2 }
    };
  }
}

new GDPlugin().init(renderChart);
